module top_module(A, B, Ci, S, Co);input A, B, Ci;
  output S, Co;
  wire sum_bit, w2, w3;

  assign sum_bit = A ^ B;          // XOR gate for A and B
  assign S = sum_bit ^ Ci;        // XOR gate for sum_bit and Ci
  assign w2 = A & B;         // AND gate for A and B
  assign w3 = sum_bit & Ci;       // AND gate for sum_bit and Ci
  assign Co = w2 | w3;       // OR gate for w2 and w3
endmodule
